You can use the `HttpClient` class in ASP.NET Core to create a proxy to another endpoint. Here's an example of how you can do this:

```csharp
using Microsoft.AspNetCore.Mvc;
using System.Net.Http;
using System.Threading.Tasks;

[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly HttpClient _httpClient;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClient = httpClientFactory.CreateClient();
    }

    [HttpGet("{*path}")]
    public async Task<IActionResult> ProxyGetAsync([FromRoute] string path)
    {
        var request = new HttpRequestMessage(HttpMethod.Get, path);
        var response = await _httpClient.SendAsync(request);

        response.EnsureSuccessStatusCode();
        return File(await response.Content.ReadAsByteArrayAsync(), response.Content.Headers.ContentType.MediaType);
    }

    [HttpPost("{*path}")]
    public async Task<IActionResult> ProxyPostAsync([FromRoute] string path)
    {
        var request = new HttpRequestMessage(HttpMethod.Post, path);
        var response = await _httpClient.SendAsync(request);

        response.EnsureSuccessStatusCode();
        return File(await response.Content.ReadAsByteArrayAsync(), response.Content.Headers.ContentType.MediaType);
    }
}
```

